import type { Message } from "discord.js";
import { logger } from "../utils/logger.js";
import { config } from "../utils/config.js";
import { awardXp, bumpMessageCount, computeMessageXp } from "../utils/rankxp.js";

const COMMAND_PREFIX = "!";
const COOLDOWN_MS = 2000;

const cooldowns = new Map<string, number>();

function isCreator(userId: string): boolean {
  return userId === "892469618063589387";
}

function isOnCooldown(userId: string): boolean {
  const last = cooldowns.get(userId);
  if (!last) return false;

  return Date.now() - last < COOLDOWN_MS;
}

function setCooldown(userId: string) {
  cooldowns.set(userId, Date.now());

  // cleanup automático simples
  setTimeout(() => cooldowns.delete(userId), COOLDOWN_MS * 2);
}

async function tryHandleRankXpCommands(message: Message, content: string): Promise<boolean> {
  if (!message.guild) return false;

  const parts = content.trim().split(/\s+/);
  const cmd = (parts.shift() ?? "").toLowerCase();

  if (cmd !== "!xp" && cmd !== "!rank") return false;

  const mention = message.mentions.users.first();
  const target = mention ?? message.author;

  if (cmd === "!xp") {
    const { getUserRank, getPosition, xpToNextLevel } = await import("../utils/rankxp.js");
    const u = await getUserRank(message.guild.id, target.id);
    const pos = await getPosition(message.guild.id, target.id);
    const prog = xpToNextLevel(u.xp);

    const who = target.id === message.author.id ? "Você" : `<@${target.id}>`;
    await message.reply(
      [
        `📈 ${who}: **Nível ${u.level}**`,
        `XP: **${u.xp}**`,
        `Próximo nível em: **${prog.remaining} XP** (meta ${prog.nextAt})`,
        `Mensagens: **${u.messageCount}**`,
        `Posição no rank: **#${pos}**`,
      ].join("\n"),
    );
    return true;
  }

  if (cmd === "!rank") {
    const { getLeaderboard } = await import("../utils/rankxp.js");
    const top = await getLeaderboard(message.guild.id, 10);

    if (top.length === 0) {
      await message.reply("Ainda não tem rank. Comecem a falar que eu começo a contar 😄");
      return true;
    }

    const lines = top.map((u) => `${u.position}. <@${u.userId}> — **Lvl ${u.level}** • **${u.xp} XP** • **${u.messageCount} msgs**`);
    await message.reply(["🏆 **Ranking (Top 10)**", ...lines].join("\n"));
    return true;
  }

  return false;
}

/**
 * Handler principal de mensagens do FAW
 */
export const handleMessage = async (message: Message) => {
  try {
    // ignora bots
    if (message.author.bot) return;

    const content = message.content?.trim();
    if (!content) return;

    const userId = message.author.id;

    // rate limit básico (anti spam)
    if (isOnCooldown(userId)) return;
    setCooldown(userId);

    // XP por mensagem (apenas em guild)
    if (message.guild) {
      // conta mensagens, e dá XP só se não for comando
      await bumpMessageCount(message.guild.id, userId).catch((err) =>
        logger.warn({ err }, "Falha ao bumpMessageCount"),
      );

      if (!content.startsWith(COMMAND_PREFIX)) {
        const xp = computeMessageXp(content);
        await awardXp(message.guild.id, userId, xp).catch((err) =>
          logger.warn({ err }, "Falha ao awardXp"),
        );
      }
    }

    // comandos simples
    if (!content.startsWith(COMMAND_PREFIX)) return;

    // rank/xp (prefix !)
    const handled = await tryHandleRankXpCommands(message, content);
    if (handled) return;

    const cmd = content.toLowerCase();

    if (cmd === "!bomb") {
      try {
        await message.reply("Boom! 💣");

        logger.info(
          {
            userId,
            tag: message.author.tag,
            command: "!bomb",
            guildId: message.guild?.id,
          },
          "Comando executado",
        );
      } catch (error) {
        logger.warn({ error, userId }, "Erro ao executar comando !bomb");
      }

      return;
    }

    // hook futuro para IA / comandos dinâmicos
    if (isCreator(userId)) {
      logger.debug({ userId, content }, "Mensagem do criador detectada");
      // espaço pra comandos avançados / execução IA
    }
  } catch (error) {
    logger.error({ error }, "Erro no handler de mensagem");
  }
};
