}

async function savePendingFwpQueue(): Promise<void> {
  await mkdir(path.dirname(PENDING_FWP_FILE), { recursive: true });
  await writeFile(PENDING_FWP_FILE, JSON.stringify(pendingFwpQueue, null, 2), "utf8");
}

async function enqueuePendingFwp(message: import("discord.js").Message, systemPrompt: string, memoryKey: string, query: string): Promise<void> {
  await loadPendingFwpQueue();
  const item: PendingFwpRequest = {
    id: `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    guildId: message.guildId ?? "",
    channelId: message.channelId,
    userId: message.author.id,
    systemPrompt,
    memoryKey,
    query,
    attempts: 0,
    nextRunAt: Date.now() + 60_000,
    createdAt: new Date().toISOString()
  };
  pendingFwpQueue.push(item);
  await savePendingFwpQueue();
  await recordMessageEvent("system", message, "Pergunta FWP enviada para fila de retry persistente.", { queueId: item.id });
}

function startPendingFwpWorker(client: import("discord.js").Client): void {
  if (pendingTimer) return;
  pendingTimer = setInterval(async () => {
    await loadPendingFwpQueue();
    const now = Date.now();
    const due = pendingFwpQueue.filter((item) => item.nextRunAt <= now).slice(0, 2);
    for (const item of due) {
      try {
        const channel = await client.channels.fetch(item.channelId).catch(() => null);
        if (!channel?.isTextBased() || !("send" in channel)) {
          pendingFwpQueue = pendingFwpQueue.filter((queued) => queued.id !== item.id);
          continue;
        }

        item.attempts++;
        const raw = await queryOllama(item.systemPrompt, item.memoryKey, item.query);
        const clean = stripFwpActionBlocks(raw);
        const embed = buildEmbed("Fawers — resposta atrasada", `<@${item.userId}> consegui cobrar a resposta que ficou devendo:\n\n${truncate(clean, 1700)}`, "action");
        await channel.send({ embeds: [embed] });
        pendingFwpQueue = pendingFwpQueue.filter((queued) => queued.id !== item.id);
        await recordMemorialEvent({ type: "ai_response", channelId: item.channelId, guildId: item.guildId, userId: item.userId, content: clean, metadata: { queued: true, queueId: item.id } });
      } catch (error) {
        item.nextRunAt = Date.now() + Math.min(10 * 60_000, 60_000 * Math.max(1, item.attempts + 1));
        if (item.attempts >= 5 || !isFwpOverloadError(error)) {
          pendingFwpQueue = pendingFwpQueue.filter((queued) => queued.id !== item.id);
        }
      }
    }
    await savePendingFwpQueue();
  }, 30_000);
  pendingTimer.unref();
}

// kept for compatibility — free mode still uses it
async function streamOllama(
  systemPrompt: string,
  memoryKey: string,
  userQuery: string,
  _onChunk: (partial: string) => void
): Promise<string> {
  return queryOllama(systemPrompt, memoryKey, userQuery);
}

async function handleFreeMode(message: import("discord.js").Message): Promise<boolean> {
  const inFreeMode = await isFreeModeActive(message.channelId);
  if (!inFreeMode) return false;

  const prefix = config.PREFIX;
  const content = message.content.trim();

  // Let prefix commands be handled normally (don't intercept them here)
  if (content.startsWith(prefix)) return false;

  try {
    const trainingData = await loadTrainingData();
    const basePrompt = trainingData.compiledIdentity || trainingData.baseIdentity;
    const systemPrompt = await buildAutonomousSystemPrompt(basePrompt + FREE_MODE_SYSTEM_SUFFIX, message);

    const author = message.author;
    const display = message.member?.displayName ?? author.username;
    const channelName = "name" in message.channel ? (message.channel as { name: string }).name : "desconhecido";
    const userQuery = `[Canal: #${channelName} | ${display} (<@${author.id}>)]: ${content || "(mensagem sem texto)"}`;

    const memoryKey = message.author.id;

    await recordMessageEvent("order_received", message, content || "(mensagem sem texto)", { mode: "free", channel: message.channelId });

    const { result: rawReply, spinnerMsg } = await runWithSpinner(
      message,
      (_spinnerMsg, setStatusText) => retryOnceAfterOverload(
        () => queryOllama(systemPrompt, memoryKey, userQuery),
        async () => {
          setStatusText(`${formatFwpError(new Error("503 unavailable"))}\n\nVou tentar cobrar a resposta de novo em 10s...`);
          await wait(10_000);
          setStatusText(null);
        }
      )
    );

    const firstPass = await executeFwpActions(message, rawReply);
    let allReports = [...firstPass.reports];
    let finalRawReply = rawReply;

    let pendingReads = firstPass.fileReads;
    const maxFollowUpPasses = config.MAX_FOLLOW_UP_PASSES ?? 4;
    for (let pass = 0; pass < maxFollowUpPasses && pendingReads.length > 0; pass++) {
      try {
        const followUpQuery = buildFileReadFollowUp(pendingReads);
        const followRaw = await queryOllama(systemPrompt, memoryKey, followUpQuery);
        const followPass = await executeFwpActions(message, followRaw);
        allReports = [...allReports, ...followPass.reports];
        if (!stripFwpActionBlocks(followRaw).startsWith("[SILENT]")) {
          finalRawReply = followRaw;
        }
        pendingReads = followPass.fileReads;
      } catch (err) {
        logger.warn({ err, pass }, "Free mode: passada de leitura falhou");
        await message.channel.send("⚠️ Tive um problema interno ao processar o arquivo. Pode repetir o pedido?").catch(() => {});
        break;
      }
    }

    const reply = stripFwpActionBlocks(finalRawReply);

    await spinnerMsg.delete().catch(() => {});

    if (reply.startsWith("[SILENT]")) {
      logger.info({ channel: message.channelId }, "Free mode: Fawers optou por silêncio");
      return true;
    }

    const finalReply = allReports.length > 0 ? `${reply}\n\n${allReports.join("\n")}` : reply;
    await message.channel.send(truncate(finalReply, 1900));
    logger.info({ channel: message.channelId, author: author.id }, "Free mode: resposta enviada");
  } catch (err) {
    logger.error({ err }, "Free mode: falha ao gerar resposta");
  }

  return true;
}

async function handleDM(message: import("discord.js").Message): Promise<boolean> {
  if (message.guild) return false;

  // Partial messages (DMs) may arrive without content — fetch the full message first
  if (message.partial) {
    try { message = await message.fetch(); } catch { return true; }
  }

  if (message.author?.bot) return false;

  const content = message.content?.trim() ?? "";
  if (!content) return true;

  // Allow ;setup fwp command in DMs
  const prefix = config.PREFIX;
  if (content.startsWith(prefix)) {
    const args = content.slice(prefix.length).trim().split(/\s+/);
    const cmd = args[0]?.toLowerCase();

    if (cmd === "setup" && args[1]?.toLowerCase() === "fwp") {
      if (!isFreeModeOwner(message.author.id)) {
        await message.reply({ embeds: [buildEmbed("Acesso negado", "Sem permissão para acessar o setup.", "warn")] });
        return true;
      }
      const row = new ActionRowBuilder<ButtonBuilder>().addComponents(
        new ButtonBuilder().setCustomId("fwp_model_beta").setLabel("Motor Beta").setStyle(ButtonStyle.Secondary),
        new ButtonBuilder().setCustomId("fwp_model_v2").setLabel("FAWER V2").setStyle(ButtonStyle.Primary),
        new ButtonBuilder().setCustomId("fwp_model_v3").setLabel("FAWER V3").setStyle(ButtonStyle.Success),
        new ButtonBuilder().setCustomId("fwp_model_v4").setLabel("FAWER V4").setStyle(ButtonStyle.Danger),
        new ButtonBuilder().setCustomId("fwp_model_v5").setLabel("FAWER V5").setStyle(ButtonStyle.Primary)
      );
      const embed = buildEmbed("Setup — Fawers", "Qual versão da Fawers você quer ativar?", "info");
      await message.reply({ embeds: [embed], components: [row] });
      return true;
    }

    if (cmd === "fwp" && args[1]?.toLowerCase() === "limpar") {
      await clearUserMemory(message.author.id);
      await message.reply({ embeds: [buildEmbed("Memória", "Memória apagada.", "ok")] });
      return true;
    }

    // If prefix but unknown command in DM, just treat the whole thing as AI query
  }

  try {
    const trainingData = await loadTrainingData();
    const systemPrompt = trainingData.compiledIdentity || trainingData.baseIdentity;
    const memoryKey = message.author.id;

    await message.channel.sendTyping().catch(() => {});
    const typingInterval = setInterval(() => message.channel.sendTyping().catch(() => {}), 8000);

    try {
      const raw = await retryOnceAfterOverload(
        () => queryOllama(systemPrompt, memoryKey, content),
        async () => { await wait(10_000); }
      );
      const reply = stripFwpActionBlocks(raw);
      if (!reply.startsWith("[SILENT]")) {
        await message.reply(truncate(reply, 1900));
      }
    } finally {
      clearInterval(typingInterval);
    }
  } catch (err) {
    logger.error({ err, userId: message.author.id }, "Falha ao responder DM");
    await message.reply("Eita, deu erro aqui. Tenta de novo em instantes.").catch(() => {});
  }

  return true;
}

async function tryHandleRankXpPrefix(message: import("discord.js").Message): Promise<boolean> {
  if (!message.guild) return false;

  const prefix = config.PREFIX;
  const raw = message.content?.trim() ?? "";
  if (!raw.startsWith(prefix)) return false;

  const content = raw.slice(prefix.length).trim();
  if (!content) return false;

  const parts = content.split(/\s+/);
  const command = parts.shift()?.toLowerCase();
  if (command !== "xp" && command !== "rank") return false;

  const mention = message.mentions.users.first();
  const target = mention ?? message.author;

  if (command === "xp") {
    const { getUserRank, getPosition, xpToNextLevel } = await import("../utils/rankxp.js");
    const u = await getUserRank(message.guild.id, target.id);
    const pos = await getPosition(message.guild.id, target.id);
    const prog = xpToNextLevel(u.xp);

    const who = target.id === message.author.id ? "Você" : `<@${target.id}>`;
    const embed = buildEmbed(
      "XP / Rank",
      [
        `📈 ${who}: **Nível ${u.level}**`,
        `XP: **${u.xp}**`,
        `Próximo nível em: **${prog.remaining} XP** (meta ${prog.nextAt})`,
        `Mensagens: **${u.messageCount}**`,
        `Posição: **#${pos}**`
      ].join("\n"),
      "action"
    );
    await message.reply({ embeds: [embed] });
    return true;
  }

  if (command === "rank") {
    const { getLeaderboard } = await import("../utils/rankxp.js");
    const top = await getLeaderboard(message.guild.id, 10);
    const body =
      top.length > 0
        ? top.map((u) => `${u.position}. <@${u.userId}> — **Lvl ${u.level}** • **${u.xp} XP** • **${u.messageCount} msgs**`).join("\n")
        : "Ainda não tem rank. Comecem a falar que eu começo a contar 😄";

    await message.reply({ embeds: [buildEmbed("🏆 Ranking (Top 10)", body, "info")] });
    return true;
  }

  return false;
}

async function awardMessageXp(message: import("discord.js").Message): Promise<void> {
  if (!message.guild) return;
  if (message.author?.bot) return;

  const prefix = config.PREFIX;
  const content = message.content?.trim() ?? "";

  // não ganha XP em comandos
  if (content.startsWith(prefix)) return;

  await bumpMessageCount(message.guild.id, message.author.id);
  const xp = computeMessageXp(content);
  await awardXp(message.guild.id, message.author.id, xp);
}

const event: BotEvent = {
  name: "messageCreate",
  async execute(message) {
    if (!config.ENABLE_PREFIX) return;
    if (!message.guild) return; // DMs handled via raw gateway in index.ts
    if (message.author?.bot) return;
    startPendingFwpWorker(message.client);

    // XP por mensagem (não-comando)
    try {
      await awardMessageXp(message);
    } catch (err) {
      logger.warn({ err }, "Falha ao processar XP por mensagem");
    }

    // rank/xp (prefix ;xp e ;rank) — antes do resto
    try {
      const handledRankXp = await tryHandleRankXpPrefix(message);
      if (handledRankXp) return;
    } catch (err) {
      logger.warn({ err }, "Falha ao processar comandos rank/xp");
    }

    // Free mode: intercept non-command messages in unlocked channels
    const handledByFreeMode = await handleFreeMode(message);
    if (handledByFreeMode) return;

    const prefix = config.PREFIX;
    if (!message.content.startsWith(prefix)) return;

    const content = message.content.slice(prefix.length).trim();
    if (!content) return;

    const parts = content.split(/\s+/);
    const command = parts.shift()?.toLowerCase();
    if (!command) return;

    await recordMessageEvent("command_received", message, content, { command, args: parts.join(" ") });

    if (command === "fw") {
      const sub = parts.shift()?.toLowerCase();
      if (sub !== "music") return;

      const action = parts[0]?.toLowerCase();
      if (action === "stop") {
        const stopped = stopMusic(message.guild.id);
        const embed = buildEmbed("FW Music", stopped ? "Pare tudo e saí da call." : "Não tinha nada tocando.", stopped ? "ok" : "info");
        await message.reply({ embeds: [embed] });
        return;
      }

      if (action === "skip") {
        const skipped = skipMusic(message.guild.id);
        const embed = buildEmbed("FW Music", skipped ? "Pulei essa faixa." : "Não tinha música ativa para pular.", skipped ? "ok" : "info");
        await message.reply({ embeds: [embed] });
        return;
      }

      if (action === "queue" || action === "fila") {
        const queue = getMusicQueue(message.guild.id);
        const body = queue.length > 0
          ? queue.slice(0, 10).map((track, index) => `${index + 1}. **${track.title}**`).join("\n")
          : "Fila vazia.";
        await message.reply({ embeds: [buildEmbed("FW Music — Fila", body, "info")] });
        return;
      }

      const query = parts.join(" ").trim();
      if (!query) {
        const fields = [
          { name: "Tocar", value: `\`${prefix}fw music <nome da música>\``, inline: false },
          { name: "Fila", value: `\`${prefix}fw music queue\``, inline: true },
          { name: "Pular", value: `\`${prefix}fw music skip\``, inline: true },
          { name: "Parar", value: `\`${prefix}fw music stop\``, inline: true }
        ];
        await message.reply({ embeds: [buildEmbedFields("FW Music — Uso", fields, "info")] });
        return;
      }

      const voice = message.member?.voice?.channel;
      if (!voice) {
        await message.reply({ embeds: [buildEmbed("FW Music", "Entra numa call primeiro pra eu saber onde tocar.", "warn")] });
        return;
      }

      const temp = await message.reply("Procurando no YouTube e preparando a call...");
      try {
        const result = await playYoutubeMusic(message.client, message.guild, voice, query, message.author.id, message.channelId);
        const embed = buildEmbed(
          "FW Music",
          [
            `Tocando/enfileirado: **[${result.title}](${result.url})**`,
            `Pedido por: <@${message.author.id}>`,
            result.position > 1 ? `Posição na fila: **${result.position}**` : "Entrando na call agora."
          ].join("\n"),
          "ok"
        );
        await temp.edit({ content: "", embeds: [embed] });
      } catch (error) {
        const msg = error instanceof Error ? error.message : "Erro desconhecido";
        const embed = buildEmbed("FW Music falhou", `Não consegui tocar isso: ${msg}`, "error");
        await temp.edit({ content: "", embeds: [embed] });
        logger.error({ error, command: "fw music", query }, "Falha ao tocar música");
      }
      return;
    }

    if (command === "ping") {
      const start = Date.now();
      const temp = await message.reply("Verificando...");
      const roundtrip = Date.now() - start;
      const ws = message.client.ws.ping;
      const fields = [
        { name: "\u{1F4E1} WebSocket", value: `${ws >= 0 ? ws : "..."}ms`, inline: true },
        { name: "\u23F1\uFE0F Roundtrip", value: `${roundtrip}ms`, inline: true }
      ];
      const embed = buildEmbedFields("Pong!", fields, "ok");
      await temp.edit({ content: "", embeds: [embed] });
      return;
